import java.util.*;class Solution{public static void main(String[]a){var s=new Scanner(System.in).nextLine();var b="";for(char c:s.toCharArray())b+=String.format("%7s",Integer.toBinaryString(c)).replace(' ','0');var r="";int i=0;while(i<b.length()){char v=b.charAt(i);int c=0;while(i<b.length()&&b.charAt(i)==v){c++;i++;}if(r.length()>0)r+=" ";r+=v=='1'?"0":"00";r+=" "+"0".repeat(c);}System.out.println(r);}}